from airflow.decorators import dag, task
from datetime import datetime

@dag(
    dag_id='energy_meter_diamond_taskflow',
    schedule=None,
    start_date=datetime(2026, 1, 1),
    catchup=False,
    tags=['energy', 'meters', 'diamond', 'taskflow'],
)
def energy_meter_diamond():

    @task()
    def download(ds=None) -> dict:
        print(f'Downloading all meter files for {ds}')
        return {'load_date': ds, 'file_count': 4}

    @task()
    def clean_region(region: str, download_result: dict) -> dict:
        rows = {'NORTH': 1_250_000, 'SOUTH': 980_000,
                'EAST': 1_100_000, 'WEST': 870_000}
        row_count = rows.get(region, 0)
        print(f'{region}: cleaned {row_count:,} rows for {download_result["load_date"]}')
        return {'region': region, 'clean_rows': row_count}

    @task()
    def quality_gate(results: list) -> dict:
        total = sum(r['clean_rows'] for r in results)
        print(f'Quality gate: {total:,} total clean rows')
        for r in results:
            print(f'  {r["region"]}: {r["clean_rows"]:,}')
        if total < 3_000_000:
            raise ValueError(f'Below threshold: {total:,} < 3,000,000')
        return {'total_rows': total, 'status': 'PASS'}

    @task()
    def load_warehouse(qc_result: dict):
        print(f'Loading {qc_result["total_rows"]:,} rows to warehouse')

    # Wire the pipeline using function calls
    dl = download()

    # Fan-out: call clean_region for each region
    regions = ['NORTH', 'SOUTH', 'EAST', 'WEST']
    clean_results = [clean_region(region=r, download_result=dl) for r in regions]

    # Fan-in: pass all results to quality gate
    qc = quality_gate(results=clean_results)

    # Continue the chain
    load_warehouse(qc_result=qc)

