As your DAGs grow with branches, dynamic tasks, and multiple processing stages, the Graph View can become cluttered. Task Groups let you visually organize related tasks into collapsible sections.
from airflow.decorators import dag, task, task_group
from datetime import datetime

@dag(dag_id='energy_organized', schedule=None, start_date=datetime(2026,1,1), catchup=False)
def organized_pipeline():

    @task_group(group_id='bronze_ingestion')
    def bronze():
        @task()
        def download():
            print('Downloading raw data')
            return '/data/raw/meters.csv'

        @task()
        def land_to_bronze(path: str):
            print(f'Landing {path} to Bronze layer')
            return {'bronze_table': 'bronze.meters'}

        path = download()
        return land_to_bronze(path)

    @task_group(group_id='silver_transform')
    def silver(bronze_result: dict):
        @task()
        def clean(source: dict):
            print(f'Cleaning from {source["bronze_table"]}')
            return {'silver_table': 'silver.meters', 'rows': 4_200_000}

        @task()
        def validate(clean_result: dict):
            print(f'Validating {clean_result["rows"]:,} rows')
            return clean_result

        cleaned = clean(bronze_result)
        return validate(cleaned)

    @task()
    def publish(silver_result: dict):
        print(f'Publishing {silver_result["rows"]:,} rows to Gold')

    bronze_out = bronze()
    silver_out = silver(bronze_out)
    publish(silver_out)

import pytest
from airflow.models import DagBag

class TestDagIntegrity:
    """Tests that all DAG files parse correctly."""

    @pytest.fixture(scope='class')
    def dagbag(self):
        """Load all DAGs from the dags/ folder."""
        return DagBag(dag_folder='dags/', include_examples=False)

    def test_no_import_errors(self, dagbag):
        """
        Every DAG file must parse without import errors.
        If this fails, a DAG has a syntax error, missing import,
        or broken top-level code.
        """
        assert len(dagbag.import_errors) == 0, \
            f'DAG import errors found: {dagbag.import_errors}'

    def test_dagbag_not_empty(self, dagbag):
        """At least one DAG should be present."""
        assert len(dagbag.dags) > 0, 'No DAGs found in dags/ folder'

    def test_no_cycles(self, dagbag):
        """All DAGs must be acyclic (no circular dependencies)."""
        for dag_id, dag in dagbag.dags.items():
            dag.test_cycle()  # Raises if cycle detected

def validate_meter_readings(readings: list) -> dict:
    """
    Validate a list of meter reading dictionaries.
    Returns a summary with valid rows, invalid rows, and quality percentage.
    """
    if not readings:
        return {'valid': [], 'invalid': [], 'quality_pct': 0.0}

    valid = []
    invalid = []

    for reading in readings:
        errors = []

        # Rule 1: daily_kwh must not be null
        if reading.get('daily_kwh') is None:
            errors.append('null_reading')

        # Rule 2: daily_kwh must not be negative
        elif reading['daily_kwh'] < 0:
            errors.append('negative_reading')

        # Rule 3: daily_kwh must be below 10,000 (physical limit)
        elif reading['daily_kwh'] > 10_000:
            errors.append('exceeds_physical_limit')

@dag(
    dag_id='platform_health_check',
    schedule='*/15 * * * *',  # Every 15 minutes
    start_date=datetime(2026, 1, 1),
    catchup=False,
    tags=['platform', 'monitoring'],
)
def health_check():

    @task()
    def check_scheduler_heartbeat():
        from airflow.models import DagBag
        db = DagBag()
        print(f'Scheduler healthy: {len(db.dags)} DAGs loaded, {len(db.import_errors)} errors')
        if db.import_errors:
            raise ValueError(f'DAG parse errors: {list(db.import_errors.keys())}')

    @task()
    def check_connections():
        from airflow.providers.postgres.hooks.postgres import PostgresHook
        pg = PostgresHook('nordgrid_warehouse')
        result = pg.get_first('SELECT 1')
        print(f'Warehouse connection healthy: {result}')
